using OneStream.Stage.Engine;
using OneStreamWorkspacesApi;
using OneStreamWorkspacesApi.V800;

namespace Workspace.__WsNamespacePrefix.__WsAssemblyName
{
    public class GBL_Helpers
    {
        public static void DictKeyAddUpdate(ref Dictionary<string, string> dict, string key, string value)
        {
            if (dict == null)
            {
                throw new ArgumentNullException(nameof(dict));
            }

            if (dict.ContainsKey(key))
            {
                dict[key] = value;
            }
            else
            {
                dict.Add(key, value);
            }
        }
        public void UpdateCustomSubstVar(ref XFSelectionChangedTaskResult result, string key, string value)
        {
            if (result.ModifiedCustomSubstVars.ContainsKey(key))
            {
                result.ModifiedCustomSubstVars.XFSetValue(key, value);
            }
            else
            {
                result.ModifiedCustomSubstVars.Add(key, value);
            }
        }

        public void UpdateCustomSubstVar(ref XFLoadDashboardTaskResult result, BRGlobals globals, string key, string value)
        {
            if (result == null)
            {
                throw new ArgumentNullException(nameof(result));
            }

            if (result.ModifiedCustomSubstVars.ContainsKey(key))
            {
                result.ModifiedCustomSubstVars.XFSetValue(key, value);
            }
            else
            {
                result.ModifiedCustomSubstVars.Add(key, value);
            }

            globals?.SetStringValue(key, value);
        }

        public string checkBlankValue(ref DataRow row, string columnName, string rawValue)
        {
            if (!row.Table.Columns.Contains(columnName)) return "Error";

            var col = row.Table.Columns[columnName];
            var isEmpty = string.IsNullOrWhiteSpace(rawValue);

            if (isEmpty)
            {
                if (col.DataType == typeof(int))
                {
                    row[columnName] = 0;
                }
                else if (col.DataType == typeof(decimal) || col.DataType == typeof(double) || col.DataType == typeof(float))
                {
                    row[columnName] = 0.0;
                }
                else if (col.DataType == typeof(bool))
                {
                    row[columnName] = false;
                }
                else
                {
                    return "Error";
                }
				return "Default";
            }
            return "Success";
        }
    }
}

﻿using System;
using System.Collections.Generic;
using System.Data;
using System.Data.Common;
using System.Globalization;
using System.IO;
using System.Linq;
using Microsoft.CSharp;
using Microsoft.Data.SqlClient;
using OneStream.Finance.Database;
using OneStream.Finance.Engine;
using OneStream.Shared.Common;
using OneStream.Shared.Database;
using OneStream.Shared.Engine;
using OneStream.Shared.Wcf;
using OneStream.Stage.Database;
using OneStream.Stage.Engine;
using OneStreamWorkspacesApi;
using OneStreamWorkspacesApi.V800;

namespace Workspace.__WsNamespacePrefix.__WsAssemblyName
{
	public class GBL_Import_CSV
	{
	    private readonly string _connectionString;

	    public GBL_Import_CSV(string connectionString)
	    {
	        _connectionString = connectionString;
	    }

	    public void Import_CSV(string csvFilePath)
	    {
	        string tableName = Path.GetFileNameWithoutExtension(csvFilePath);

	        // 1. Read system tables for schema info
	        var schemaTable = GetTableSchema(tableName);
	        if (schemaTable.Rows.Count == 0)
	            throw new Exception($"Table '{tableName}' does not exist.");

	        // 2. Get primary keys
	        var primaryKeys = GetPrimaryKeys(tableName);

	        // 3. Read CSV
	        var csvLines = File.ReadAllLines(csvFilePath);
	        var csvColumns = csvLines[0].Split(',');

	        // 4. Validate columns
	        foreach (var col in csvColumns)
	        {
	            if (!schemaTable.AsEnumerable().Any(r => r["COLUMN_NAME"].ToString().Equals(col, StringComparison.OrdinalIgnoreCase)))
	                throw new Exception($"Column '{col}' does not exist in table '{tableName}'.");
	        }

	        // 5. Prepare DataTable for bulk copy
	        var dataTable = new DataTable();
	        foreach (var col in csvColumns)
	        {
	            var colType = schemaTable.AsEnumerable()
	                .First(r => r["COLUMN_NAME"].ToString().Equals(col, StringComparison.OrdinalIgnoreCase))["DATA_TYPE"].ToString();
	            dataTable.Columns.Add(col, GetTypeFromSqlType(colType));
	        }

	        // 6. Fill DataTable
	        foreach (var line in csvLines.Skip(1))
	        {
	            var values = line.Split(',');
	            dataTable.Rows.Add(values);
	        }

	        // 7. Merge/Upsert logic (simple example: delete and insert)
	        using (var conn = new SqlConnection(_connectionString))
	        {
	            conn.Open();
	            // Optional: Use transaction
	            using (var tran = conn.BeginTransaction())
	            {
	                // Example: Delete existing rows with matching PKs
	                foreach (DataRow row in dataTable.Rows)
	                {
	                    string whereClause = string.Join(" AND ", primaryKeys.Select(pk => $"{pk} = '{row[pk]}'"));
	                    string deleteSql = $"DELETE FROM [{tableName}] WHERE {whereClause}";
	                    using (var cmd = new SqlCommand(deleteSql, conn, tran))
	                    {
	                        cmd.ExecuteNonQuery();
	                    }
	                }

	                // Bulk insert
	                using (var bulk = new SqlBulkCopy(conn, SqlBulkCopyOptions.Default, tran))
	                {
	                    bulk.DestinationTableName = tableName;
	                    bulk.WriteToServer(dataTable);
	                }

	                tran.Commit();
	            }
	        }
	    }

	    private DataTable GetTableSchema(string tableName)
	    {
	        using (var conn = new SqlConnection(_connectionString))
	        {
	            string sql = @"SELECT COLUMN_NAME, DATA_TYPE 
	                           FROM INFORMATION_SCHEMA.COLUMNS 
	                           WHERE TABLE_NAME = @TableName";
	            using (var cmd = new SqlCommand(sql, conn))
	            {
	                cmd.Parameters.AddWithValue("@TableName", tableName);
	                var dt = new DataTable();
	                conn.Open();
	                dt.Load(cmd.ExecuteReader());
	                return dt;
	            }
	        }
	    }

	    private string[] GetPrimaryKeys(string tableName)
	    {
	        using (var conn = new SqlConnection(_connectionString))
	        {
	            string sql = @"SELECT COLUMN_NAME 
	                           FROM INFORMATION_SCHEMA.KEY_COLUMN_USAGE 
	                           WHERE OBJECTPROPERTY(OBJECT_ID(CONSTRAINT_SCHEMA + '.' + QUOTENAME(CONSTRAINT_NAME)), 'IsPrimaryKey') = 1
	                           AND TABLE_NAME = @TableName";
	            using (var cmd = new SqlCommand(sql, conn))
	            {
	                cmd.Parameters.AddWithValue("@TableName", tableName);
	                var dt = new DataTable();
	                conn.Open();
	                dt.Load(cmd.ExecuteReader());
	                return dt.AsEnumerable().Select(r => r["COLUMN_NAME"].ToString()).ToArray();
	            }
	        }
	    }

	    private Type GetTypeFromSqlType(string sqlType)
	    {
	        switch (sqlType.ToLower())
	        {
	            case "int": return typeof(int);
	            case "bigint": return typeof(long);
	            case "bit": return typeof(bool);
	            case "datetime": return typeof(DateTime);
	            case "decimal": return typeof(decimal);
	            case "float": return typeof(double);
	            case "nvarchar":
	            case "varchar":
	            case "nchar":
	            case "char":
	            case "text":
	                return typeof(string);
	            default: return typeof(string);
	        }
	    }
	}
}

using System;
using System.Collections.Generic;
using System.Data;
using System.Data.Common;
using System.Globalization;
using System.IO;
using System.Linq;
using System.Text;
using Microsoft.CSharp;
using Microsoft.Data.SqlClient;
using OneStream.Finance.Database;
using OneStream.Finance.Engine;
using OneStream.Shared.Common;
using OneStream.Shared.Database;
using OneStream.Shared.Engine;
using OneStream.Shared.Wcf;
using OneStream.Stage.Database;
using OneStream.Stage.Engine;
using OneStreamWorkspacesApi;
using OneStreamWorkspacesApi.V800;

namespace Workspace.__WsNamespacePrefix.__WsAssemblyName
{
    /// <summary>
    /// Generic SQL Command Builder that dynamically generates INSERT/UPDATE/DELETE commands
    /// based on DataTable schema. This eliminates hardcoded SQL statements and provides
    /// automatic synchronization when schema changes occur.
    /// </summary>
    public class GBL_SQL_Command_Builder
    {
        private readonly SqlConnection _connection;
        private readonly string _tableName;
        private readonly DataTable _dataTable;
        private readonly List<string> _primaryKeyColumns;
        private readonly List<string> _excludeFromUpdate;
        private readonly List<string> _excludeFromInsert;

        /// <summary>
        /// Initialize the SQL Command Builder
        /// </summary>
        /// <param name="connection">SQL connection to use</param>
        /// <param name="tableName">Name of the table to generate commands for</param>
        /// <param name="dataTable">DataTable with schema information</param>
        public GBL_SQL_Command_Builder(SqlConnection connection, string tableName, DataTable dataTable)
        {
            _connection = connection;
            _tableName = tableName;
            _dataTable = dataTable;
            _primaryKeyColumns = new List<string>();
            _excludeFromUpdate = new List<string>();
            _excludeFromInsert = new List<string>();
        }

        public (string[] PKs, string[] UpdEx, string[] InsEx) gettableDefsfromConfig(SessionInfo si, string tableName)
        {
            var tableDef = new Dictionary<string, (string[] PKs, string[] UpdEx, string[] InsEx)>(StringComparer.OrdinalIgnoreCase)
            {
				{ "FMM_ActConfig", (new[] { "ActConfigID" }, new[] { "ActConfigID", "CreateDate", "CreateUser" }, new[] { "ActConfigID" }) },
				{ "FMM_CubeConfig", (new[] { "CubeConfigID" }, new[] { "CubeConfigID", "CreateDate", "CreateUser" }, new[] { "CubeConfigID" }) },
                { "FMM_CustTable", (new[] { "CustTableID" }, new[] { "CustTableID", "CreateDate", "CreateUser" }, new[] { "CustTableID" }) },
                { "FMM_SrcCellConfig", (new[] { "SrcCellConfigID" }, new[] { "SrcCellConfigID", "CreateDate", "CreateUser" }, new[] { "SrcCellConfigID" }) },
                { "FMM_CustTableFK", (new[] { "CustTableFKID" }, new[] { "CustTableFKID", "CreateDate" }, new[] { "CustTableFKID" }) }
            };

            if (tableDef.TryGetValue(tableName, out var def))
            {
                return def;
            }
            else
            {
                // Call the fallback function to query the database
                return GetTableDefsFromMetadata(si, tableName);
            }
        }

        private (string[] PKs, string[] UpdEx, string[] InsEx) GetTableDefsFromMetadata(SessionInfo si, string tableName)
        {
            var pks = new List<string>();

            // Query SQL Server Schema for Primary Keys
            var sql = @"
                SELECT COLUMN_NAME 
                FROM INFORMATION_SCHEMA.KEY_COLUMN_USAGE 
                WHERE TABLE_NAME = @tableName 
                AND OBJECTPROPERTY(OBJECT_ID(CONSTRAINT_SCHEMA + '.' + CONSTRAINT_NAME), 'IsPrimaryKey') = 1";

            using (var cmd = new SqlCommand(sql, _connection))
            {
                cmd.Parameters.AddWithValue("@tableName", tableName);

                using (var reader = cmd.ExecuteReader())
                {
                    while (reader.Read())
                    {
                        pks.Add(reader["COLUMN_NAME"].ToString());
                    }
                }
            }

            // Convert list to array
            string[] pkArray = pks.ToArray();

            // In a generic metadata fallback, we usually exclude PKs from both 
            // updates and inserts assuming they are Identity columns.
            return (pkArray, pkArray, pkArray);
        }

        public void SetPrimaryKey(params string[] columnNames)
        {
            _primaryKeyColumns.Clear();
            _primaryKeyColumns.AddRange(columnNames);
        }

        public void ExcludeFromUpdate(params string[] columnNames)
        {
            _excludeFromUpdate.Clear();
            _excludeFromUpdate.AddRange(columnNames);
        }

        /// <summary>
        /// Set columns to exclude from INSERT operations (e.g., identity columns)
        /// </summary>
        public void ExcludeFromInsert(params string[] columnNames)
        {
            _excludeFromInsert.Clear();
            _excludeFromInsert.AddRange(columnNames);
        }

        /// <summary>
        /// Build INSERT command based on DataTable schema
        /// </summary>
        public SqlCommand BuildInsertCommand(SqlTransaction transaction = null)
        {
            var columns = new List<string>();
            var parameters = new List<string>();

            foreach (DataColumn col in _dataTable.Columns)
            {
                if (_excludeFromInsert.Contains(col.ColumnName))
                    continue;

                columns.Add(col.ColumnName);
                parameters.Add($"@{col.ColumnName}");
            }

            var sql = $@"
                INSERT INTO {_tableName} (
                    {string.Join(", ", columns)}
                ) VALUES (
                    {string.Join(", ", parameters)}
                )";

            var command = transaction != null
                ? new SqlCommand(sql, _connection, transaction)
                : new SqlCommand(sql, _connection);

            command.UpdatedRowSource = UpdateRowSource.None;

            foreach (DataColumn col in _dataTable.Columns)
            {
                if (_excludeFromInsert.Contains(col.ColumnName))
                    continue;

                var param = command.Parameters.Add($"@{col.ColumnName}", GetSqlDbType(col.DataType));
                param.SourceColumn = col.ColumnName;

                if (col.MaxLength > 0 && (col.DataType == typeof(string)))
                {
                    param.Size = col.MaxLength;
                }
            }

            return command;
        }

        /// <summary>
        /// Build UPDATE command based on DataTable schema
        /// </summary>
        public SqlCommand BuildUpdateCommand(SqlTransaction transaction = null)
        {
            if (_primaryKeyColumns.Count == 0)
            {
                throw new InvalidOperationException("Primary key columns must be set before building UPDATE command");
            }

            var setClauses = new List<string>();
            var whereClauses = new List<string>();

            foreach (DataColumn col in _dataTable.Columns)
            {
                if (_primaryKeyColumns.Contains(col.ColumnName))
                {
                    whereClauses.Add($"{col.ColumnName} = @{col.ColumnName}");
                }
                else if (!_excludeFromUpdate.Contains(col.ColumnName))
                {
                    setClauses.Add($"{col.ColumnName} = @{col.ColumnName}");
                }
            }

            var sql = $@"
                UPDATE {_tableName} SET
                    {string.Join(",\n                    ", setClauses)}
                WHERE {string.Join(" AND ", whereClauses)}";

            var command = transaction != null
                ? new SqlCommand(sql, _connection, transaction)
                : new SqlCommand(sql, _connection);

            command.UpdatedRowSource = UpdateRowSource.None;

            // Add parameters for SET clause
            foreach (DataColumn col in _dataTable.Columns)
            {
                if (_primaryKeyColumns.Contains(col.ColumnName) || _excludeFromUpdate.Contains(col.ColumnName))
                    continue;

                var param = command.Parameters.Add($"@{col.ColumnName}", GetSqlDbType(col.DataType));
                param.SourceColumn = col.ColumnName;

                if (col.MaxLength > 0 && (col.DataType == typeof(string)))
                {
                    param.Size = col.MaxLength;
                }
            }

            // Add parameters for WHERE clause (primary keys)
            foreach (var pkColumn in _primaryKeyColumns)
            {
                var col = _dataTable.Columns[pkColumn];
                var param = command.Parameters.Add($"@{pkColumn}", GetSqlDbType(col.DataType));
                param.SourceColumn = pkColumn;
                param.SourceVersion = DataRowVersion.Original;

                if (col.MaxLength > 0 && (col.DataType == typeof(string)))
                {
                    param.Size = col.MaxLength;
                }
            }

            return command;
        }

        /// <summary>
        /// Build DELETE command based on primary key columns
        /// </summary>
        public SqlCommand BuildDeleteCommand(SqlTransaction transaction = null)
        {
            if (_primaryKeyColumns.Count == 0)
            {
                throw new InvalidOperationException("Primary key columns must be set before building DELETE command");
            }

            var whereClauses = new List<string>();

            foreach (var pkColumn in _primaryKeyColumns)
            {
                whereClauses.Add($"{pkColumn} = @{pkColumn}");
            }

            var sql = $@"
                DELETE FROM {_tableName}
                WHERE {string.Join(" AND ", whereClauses)}";

            var command = transaction != null
                ? new SqlCommand(sql, _connection, transaction)
                : new SqlCommand(sql, _connection);

            command.UpdatedRowSource = UpdateRowSource.None;

            foreach (var pkColumn in _primaryKeyColumns)
            {
                var col = _dataTable.Columns[pkColumn];
                var param = command.Parameters.Add($"@{pkColumn}", GetSqlDbType(col.DataType));
                param.SourceColumn = pkColumn;
                param.SourceVersion = DataRowVersion.Original;

                if (col.MaxLength > 0 && (col.DataType == typeof(string)))
                {
                    param.Size = col.MaxLength;
                }
            }

            return command;
        }

        /// <summary>
        /// Configure SqlDataAdapter with dynamically generated commands
        /// </summary>
        public void ConfigureAdapter(SqlDataAdapter adapter, SqlTransaction transaction = null)
        {
            adapter.InsertCommand = BuildInsertCommand(transaction);
            adapter.UpdateCommand = BuildUpdateCommand(transaction);
            adapter.DeleteCommand = BuildDeleteCommand(transaction);
            //adapter.UpdateBatchSize = ; // Set batch size for performance
        }

        /// <summary>
        /// Map .NET types to SQL Server types
        /// </summary>
        private SqlDbType GetSqlDbType(Type type)
        {
            if (type == typeof(int))
                return SqlDbType.Int;
            if (type == typeof(long))
                return SqlDbType.BigInt;
            if (type == typeof(short))
                return SqlDbType.SmallInt;
            if (type == typeof(byte))
                return SqlDbType.TinyInt;
            if (type == typeof(bool))
                return SqlDbType.Bit;
            if (type == typeof(DateTime))
                return SqlDbType.DateTime;
            if (type == typeof(decimal))
                return SqlDbType.Decimal;
            if (type == typeof(double))
                return SqlDbType.Float;
            if (type == typeof(float))
                return SqlDbType.Real;
            if (type == typeof(Guid))
                return SqlDbType.UniqueIdentifier;
            if (type == typeof(byte[]))
                return SqlDbType.VarBinary;
            if (type == typeof(string))
                return SqlDbType.NVarChar;

            return SqlDbType.NVarChar; // Default fallback
        }
    }
}

using System;
using System.Collections.Generic;
using System.Data;
using System.Data.Common;
using System.Globalization;
using System.IO;
using System.Linq;
using Microsoft.CSharp;
using Microsoft.Data.SqlClient;
using OneStream.Finance.Database;
using OneStream.Finance.Engine;
using OneStream.Shared.Common;
using OneStream.Shared.Database;
using OneStream.Shared.Engine;
using OneStream.Shared.Wcf;
using OneStream.Stage.Database;
using OneStream.Stage.Engine;
using OneStreamWorkspacesApi;
using OneStreamWorkspacesApi.V800;
using OneStreamWorkspacesApi.V820;

namespace Workspace.__WsNamespacePrefix.__WsAssemblyName
{
    public class SQA_GBL_Command_Builder
    {
        private readonly SqlConnection _connection;

        public SQA_GBL_Command_Builder(SessionInfo si, SqlConnection connection)
        {
            _connection = connection;
        }


       public void UpdateTable(SessionInfo si, string tableName, DataTable dt, SqlDataAdapter sqa)
        {
            _ = si;
            var builder = new GBL_SQL_Command_Builder(_connection, tableName, dt);

            var tableDef = builder.gettableDefsfromConfig(si, tableName);

            string[] FilterColumns(IEnumerable<string>? columns) =>
            (columns ?? Array.Empty<string>())
                .Where(dt.Columns.Contains)
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToArray();


            var resolvedPrimaryKeys = FilterColumns(tableDef.PKs);
            if (resolvedPrimaryKeys.Length == 0)
            {
            throw new XFException("Primary key columns must exist in the DataTable.");
            }

            var updateExclusions = FilterColumns(tableDef.UpdEx);
            var insertExclusions = FilterColumns(tableDef.InsEx);

            using var transaction = _connection.BeginTransaction();
            try
            {

            builder.SetPrimaryKey(resolvedPrimaryKeys);

            if (updateExclusions.Length > 0)
            {
                builder.ExcludeFromUpdate(updateExclusions);
            }

            if (insertExclusions.Length > 0)
            {
                builder.ExcludeFromInsert(insertExclusions);
            }

            builder.ConfigureAdapter(sqa, transaction);

            sqa.Update(dt);
            transaction.Commit();

            }
            catch (Exception ex)
            {
            transaction.Rollback();
            throw new XFException(si, ex);
            }
            finally
            {
            sqa.InsertCommand = null;
            sqa.UpdateCommand = null;
            sqa.DeleteCommand = null;
            }
        }

        public GBL_SQL_Command_Builder GetCommandBuilder(SessionInfo si, string tableName, DataTable dt)
        {
            return new GBL_SQL_Command_Builder(_connection, tableName, dt);
        }

        /// <summary>
        /// Dynamically fill a DataTable from a SQL query with optional parameters
        /// </summary>
        /// <param name="si">SessionInfo</param>
        /// <param name="sqa">SqlDataAdapter to use for the Fill operation</param>
        /// <param name="dt">DataTable to fill with results</param>
        /// <param name="sql">SQL SELECT query to execute</param>
        /// <param name="sqlparams">Optional SQL parameters for the query</param>
        public void FillDataTable(SessionInfo si, SqlDataAdapter sqa, DataTable dt, string sql, params SqlParameter[] sqlparams)
        {
            using (SqlCommand command = new SqlCommand(sql, _connection))
            {
                command.CommandType = CommandType.Text;
                if (sqlparams?.Length > 0)
                {
                    command.Parameters.AddRange(sqlparams);
                }

                sqa.SelectCommand = command;
                sqa.Fill(dt);
                command.Parameters.Clear();
                sqa.SelectCommand = null;
            }
        }

        /// <summary>
        /// Merge source DataTable into target DataTable with primary key preservation
        /// </summary>
        /// <param name="si">SessionInfo</param>
        /// <param name="targetDt">Target DataTable to merge into</param>
        /// <param name="sourceDt">Source DataTable to merge from</param>
        /// <param name="preserveChanges">True to preserve changes in the target; false to overwrite</param>
        /// <param name="missingSchemaAction">Action to take when schema doesn't match</param>
        public void MergeDataTable(SessionInfo si, DataTable targetDt, DataTable sourceDt, 
            bool preserveChanges = true, MissingSchemaAction missingSchemaAction = MissingSchemaAction.Error)
        {
            try
            {
                targetDt.Merge(sourceDt, preserveChanges, missingSchemaAction);
            }
            catch (Exception ex)
            {
                throw new XFException($"Error merging DataTable: {ex.Message}");
            }
        }

        /// <summary>
        /// Merge source DataTable into target DataTable with composite primary key handling
        /// </summary>
        /// <param name="si">SessionInfo</param>
        /// <param name="targetDt">Target DataTable to merge into</param>
        /// <param name="sourceDt">Source DataTable to merge from</param>
        /// <param name="primaryKeyColumns">Array of column names that form the composite primary key</param>
        /// <param name="preserveChanges">True to preserve changes in the target; false to overwrite</param>
        public void MergeDataTableWithKeys(SessionInfo si, DataTable targetDt, DataTable sourceDt, 
            string[] primaryKeyColumns, bool preserveChanges = false)
        {
            try
            {
                // Set primary keys on both tables if not already set
                if (targetDt.PrimaryKey == null || targetDt.PrimaryKey.Length == 0)
                {
                    var targetKeys = primaryKeyColumns.Select(col => 
                    {
                        if (targetDt.Columns[col] == null)
                            throw new ArgumentException($"Column '{col}' does not exist in target DataTable");
                        return targetDt.Columns[col];
                    }).ToArray();
                    targetDt.PrimaryKey = targetKeys;
                }

                if (sourceDt.PrimaryKey == null || sourceDt.PrimaryKey.Length == 0)
                {
                    var sourceKeys = primaryKeyColumns.Select(col => 
                    {
                        if (sourceDt.Columns[col] == null)
                            throw new ArgumentException($"Column '{col}' does not exist in source DataTable");
                        return sourceDt.Columns[col];
                    }).ToArray();
                    sourceDt.PrimaryKey = sourceKeys;
                }

                // Perform the merge
                targetDt.Merge(sourceDt, preserveChanges, MissingSchemaAction.Add);
            }
            catch (Exception ex)
            {
                throw new XFException($"Error merging DataTable with keys: {ex.Message}");
            }
        }
    }
}

