    public class SQL_GBL_Get_DataSets
    {
        private readonly SqlConnection _connection;

        public SQL_GBL_Get_DataSets(SessionInfo si, SqlConnection connection)
        {
            _connection = connection;
        }

        public void Fill_Get_GBL_DT(SessionInfo si, SqlDataAdapter sqa, DataTable dt, string sql, params SqlParameter[] sqlparams)
        {
            using (SqlCommand command = new SqlCommand(sql, _connection))
            {
                command.CommandType = CommandType.Text;
                if (sqlparams != null)
                {
                    command.Parameters.AddRange(sqlparams);
                }

                sqa.SelectCommand = command;
                sqa.Fill(dt);
				command.Parameters.Clear();
            }
        }
    }
